// AWS Cloud Practitioner (CLF-C02) - 150 Questions
const CCP_QUESTIONS = [
{id:'ccp1',exams:['ccp'],domain:'Cloud Concepts',text:'What is the primary benefit of cloud computing over traditional on-premises infrastructure?',options:['Guaranteed 100% uptime','Trade fixed expenses for variable expenses','Eliminates the need for IT staff','Provides free storage'],correct:1,explanation:'Cloud computing lets you pay only for what you use (variable expenses) rather than investing in data centers upfront (fixed expenses). This is a core advantage of cloud adoption.'},
{id:'ccp2',exams:['ccp'],domain:'Cloud Concepts',text:'Which AWS support plan provides a Technical Account Manager (TAM)?',options:['Developer','Business','Enterprise On-Ramp','Enterprise'],correct:3,explanation:'The Enterprise support plan includes a dedicated Technical Account Manager (TAM) who provides proactive guidance and advocacy.'},
{id:'ccp3',exams:['ccp','saa'],domain:'Cloud Concepts',text:'What does the AWS Shared Responsibility Model state about customer responsibility?',options:['AWS manages everything','Customers are responsible for security IN the cloud','Customers are responsible for security OF the cloud','AWS handles patching of all customer EC2 instances'],correct:1,explanation:'Customers are responsible for security IN the cloud (data, OS, apps), while AWS handles security OF the cloud (physical infrastructure, hypervisor).'},
{id:'ccp4',exams:['ccp'],domain:'Cloud Concepts',text:"Which of the following best describes 'elasticity' in cloud computing?",options:['The ability to move workloads between cloud providers','The ability to scale resources up or down automatically based on demand','The durability of stored data','The geographic distribution of data centers'],correct:1,explanation:'Elasticity is the ability to automatically acquire resources as needed and release them when no longer required.'},
{id:'ccp5',exams:['ccp','saa'],domain:'Cloud Concepts',text:'What is an AWS Region?',options:['A single data center','A collection of Availability Zones in a geographic area','An edge location for caching content','A logical grouping of AWS accounts'],correct:1,explanation:'An AWS Region is a physical location containing multiple isolated Availability Zones within a geographic area.'},
{id:'ccp6',exams:['ccp','saa','dva'],domain:'Security & Compliance',text:'Which AWS service provides a managed firewall to protect web applications from common exploits?',options:['AWS Shield','AWS WAF','Amazon GuardDuty','AWS Firewall Manager'],correct:1,explanation:'AWS WAF (Web Application Firewall) protects web applications from common exploits like SQL injection and XSS.'},
{id:'ccp7',exams:['ccp','saa','dva'],domain:'Security & Compliance',text:'What is AWS IAM used for?',options:['Monitoring application performance','Managing user access and permissions to AWS services','Encrypting data at rest','Providing DDoS protection'],correct:1,explanation:'AWS IAM manages access to AWS services and resources securely through users, groups, roles, and policies.'},
{id:'ccp8',exams:['ccp','saa'],domain:'Security & Compliance',text:'Which AWS service helps detect threats by continuously monitoring your AWS accounts?',options:['AWS Inspector','Amazon Macie','Amazon GuardDuty','AWS Config'],correct:2,explanation:'Amazon GuardDuty is a threat detection service that continuously monitors for malicious activity and unauthorized behavior.'},
{id:'ccp9',exams:['ccp','saa','dva'],domain:'Security & Compliance',text:'What is the principle of least privilege?',options:['Users should have the most permissions possible','Granting only the minimum permissions needed to perform a task','All users share the same permissions','Admins have unlimited access'],correct:1,explanation:'Least privilege means giving users, apps, and systems only the permissions they need and nothing more.'},
{id:'ccp10',exams:['ccp','saa'],domain:'Security & Compliance',text:'Which service provides hardware-based key storage for regulatory compliance?',options:['AWS KMS','AWS CloudHSM','AWS Secrets Manager','AWS Certificate Manager'],correct:1,explanation:'AWS CloudHSM provides dedicated hardware security modules (HSMs) for cryptographic key storage meeting strict compliance requirements.'},
{id:'ccp11',exams:['ccp','dva'],domain:'Technology',text:'Which AWS compute service runs code without provisioning or managing servers?',options:['Amazon EC2','Amazon ECS','AWS Lambda','Amazon Lightsail'],correct:2,explanation:'AWS Lambda is a serverless compute service that runs code in response to events without provisioning servers.'},
{id:'ccp12',exams:['ccp','saa','dva'],domain:'Technology',text:'What is Amazon S3 primarily used for?',options:['Running virtual machines','Object storage','Relational database hosting','Content delivery'],correct:1,explanation:'Amazon S3 is an object storage service offering scalability, durability, and performance for storing any amount of data.'},
{id:'ccp13',exams:['ccp','saa','dva'],domain:'Technology',text:'Which AWS service is a fully managed relational database service?',options:['Amazon DynamoDB','Amazon Redshift','Amazon RDS','Amazon ElastiCache'],correct:2,explanation:'Amazon RDS makes it easy to set up, operate, and scale relational databases including MySQL, PostgreSQL, Oracle, and SQL Server.'},
{id:'ccp14',exams:['ccp','saa'],domain:'Technology',text:'What is Amazon CloudFront?',options:['A DNS service','A content delivery network (CDN)','A virtual private cloud','A monitoring service'],correct:1,explanation:'Amazon CloudFront is a CDN that securely delivers data, videos, applications, and APIs globally with low latency.'},
{id:'ccp15',exams:['ccp','saa'],domain:'Technology',text:'Which service enables running containerized applications on AWS without managing servers?',options:['Amazon ECS on EC2','AWS Fargate','Amazon EC2 Auto Scaling','AWS Elastic Beanstalk'],correct:1,explanation:'AWS Fargate is a serverless compute engine for containers, removing the need to provision and manage servers.'},
{id:'ccp16',exams:['ccp','saa'],domain:'Technology',text:'What does Amazon VPC allow you to do?',options:['Monitor application metrics','Launch AWS resources in an isolated virtual network','Manage DNS records','Cache frequently accessed data'],correct:1,explanation:'Amazon VPC lets you provision a logically isolated section of AWS Cloud where you launch resources in a virtual network you define.'},
{id:'ccp17',exams:['ccp','saa','dva'],domain:'Technology',text:'Which AWS service provides a fully managed NoSQL database?',options:['Amazon RDS','Amazon Aurora','Amazon DynamoDB','Amazon Redshift'],correct:2,explanation:'Amazon DynamoDB is a fully managed, serverless key-value NoSQL database with single-digit millisecond performance.'},
{id:'ccp18',exams:['ccp','dva'],domain:'Technology',text:'What is AWS Elastic Beanstalk?',options:['A container orchestration service','A PaaS that automatically handles deployment, capacity, and scaling','A serverless function service','A managed Kubernetes service'],correct:1,explanation:'AWS Elastic Beanstalk automatically handles deployment, capacity provisioning, load balancing, auto-scaling, and health monitoring.'},
{id:'ccp19',exams:['ccp'],domain:'Billing & Pricing',text:'What is the AWS Free Tier?',options:['A support plan for free','Services that are always free for all customers','A program offering free usage of certain services for new AWS customers','Free training and certification'],correct:2,explanation:'The AWS Free Tier lets new customers explore AWS services free of charge, including Always Free, 12 Months Free, and short-term trials.'},
{id:'ccp20',exams:['ccp'],domain:'Billing & Pricing',text:'Which pricing model offers the largest discount for EC2 instances in exchange for a commitment?',options:['On-Demand','Spot Instances','Reserved Instances','Dedicated Hosts'],correct:2,explanation:'Reserved Instances offer up to 72% discount over On-Demand pricing in exchange for a 1 or 3-year commitment.'},
{id:'ccp21',exams:['ccp'],domain:'Billing & Pricing',text:'What is AWS Cost Explorer used for?',options:['Monitoring security threats','Visualizing and analyzing AWS costs and usage over time','Managing IAM permissions','Setting up billing alerts'],correct:1,explanation:'AWS Cost Explorer lets you visualize, understand, and manage your AWS costs and usage with intuitive graphs and filtering.'},
{id:'ccp22',exams:['ccp'],domain:'Billing & Pricing',text:'Which AWS tool helps estimate costs before deploying resources?',options:['AWS Cost Explorer','AWS Budgets','AWS Pricing Calculator','AWS Trusted Advisor'],correct:2,explanation:'The AWS Pricing Calculator allows you to estimate the cost of AWS services for your use case before deploying anything.'},
{id:'ccp23',exams:['ccp'],domain:'Billing & Pricing',text:'What are Spot Instances?',options:['Reserved capacity for a specific AZ','Unused EC2 capacity available at steep discounts with possible interruption','Instances dedicated to a single customer','On-demand instances with enhanced networking'],correct:1,explanation:'Spot Instances use spare EC2 capacity at up to 90% off On-Demand prices. AWS can reclaim them with a 2-minute warning.'},
{id:'ccp24',exams:['ccp'],domain:'Cloud Concepts',text:'Which of the following is an example of horizontal scaling?',options:['Upgrading an EC2 instance to a larger type','Adding more EC2 instances to handle increased load','Increasing RAM on an existing server','Upgrading the CPU on a database server'],correct:1,explanation:'Horizontal scaling (scale out) adds more instances to distribute load. Vertical scaling (scale up) upgrades existing resources.'},
{id:'ccp25',exams:['ccp'],domain:'Security & Compliance',text:'What is AWS Artifact?',options:['A CI/CD pipeline service','A compliance and audit reports portal','A container registry','An infrastructure-as-code tool'],correct:1,explanation:'AWS Artifact is a self-service portal for on-demand access to AWS compliance reports like SOC, ISO certifications, and PCI.'},
{id:'ccp26',exams:['ccp','saa','dva'],domain:'Technology',text:'Which service automates infrastructure deployment using code?',options:['AWS CodeDeploy','AWS CloudFormation','AWS CodePipeline','AWS CodeBuild'],correct:1,explanation:'AWS CloudFormation lets you model and provision AWS resources by treating infrastructure as code using JSON or YAML templates.'},
{id:'ccp27',exams:['ccp','saa'],domain:'Technology',text:'What is Amazon Route 53?',options:['A managed Kubernetes service','A scalable DNS and domain registration service','A dedicated connection to AWS','A caching service'],correct:1,explanation:'Amazon Route 53 is a highly available and scalable DNS web service that routes requests to internet applications.'},
{id:'ccp28',exams:['ccp','saa','dva'],domain:'Security & Compliance',text:'Which AWS service monitors and records API calls made on your account?',options:['Amazon CloudWatch','AWS CloudTrail','AWS Config','Amazon Inspector'],correct:1,explanation:'AWS CloudTrail records API calls in your AWS account, providing history for security analysis, resource tracking, and compliance auditing.'},
{id:'ccp29',exams:['ccp','dva'],domain:'Technology',text:'What does Amazon SQS provide?',options:['Real-time video streaming','A fully managed message queuing service','A push notification service','A DNS service'],correct:1,explanation:'Amazon SQS is a fully managed message queuing service for decoupling and scaling microservices and distributed systems.'},
{id:'ccp30',exams:['ccp'],domain:'Cloud Concepts',text:'What are the six pillars of the AWS Well-Architected Framework?',options:['Security, Reliability, Performance, Cost, Sustainability, Simplicity','Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, Sustainability','Speed, Security, Scalability, Storage, Serverless, Support','Availability, Security, Monitoring, Optimization, Compliance, Cost'],correct:1,explanation:'The six pillars are: Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, and Sustainability.'},
{id:'ccp31',exams:['ccp','saa'],domain:'Technology',text:'Which AWS service provides a managed Kubernetes service?',options:['Amazon ECS','AWS Fargate','Amazon EKS','AWS Batch'],correct:2,explanation:'Amazon EKS is a fully managed Kubernetes service that makes it easy to deploy, manage, and scale containerized applications.'},
{id:'ccp32',exams:['ccp'],domain:'Billing & Pricing',text:'What is Consolidated Billing in AWS Organizations?',options:['Separates billing by department','Combines usage and billing across multiple accounts for potential volume discounts','A detailed line-item invoice for EC2 only','A monthly report sent by email'],correct:1,explanation:'Consolidated Billing lets you consolidate payment for multiple AWS accounts and potentially benefit from combined usage pricing.'},
{id:'ccp33',exams:['ccp','saa'],domain:'Security & Compliance',text:'What is Amazon Inspector used for?',options:['Monitoring cost anomalies','Automated security vulnerability assessment of EC2 and container images','Detecting unusual network activity','Managing SSL certificates'],correct:1,explanation:'Amazon Inspector is an automated vulnerability management service scanning EC2 instances and container images for vulnerabilities.'},
{id:'ccp34',exams:['ccp'],domain:'Cloud Concepts',text:'What is the definition of high availability?',options:['A system that never goes down','A system designed to minimize downtime and remain operational despite failures','A system with 100% SLA guarantee','Deploying resources across all regions'],correct:1,explanation:'High availability means systems designed to operate continuously with minimal downtime through redundancy and automatic failover.'},
{id:'ccp35',exams:['ccp','saa'],domain:'Security & Compliance',text:'Which AWS service helps protect against DDoS attacks automatically at no extra cost?',options:['AWS WAF','AWS Shield Standard','AWS Firewall Manager','Amazon GuardDuty'],correct:1,explanation:'AWS Shield Standard is automatically included with all accounts at no extra cost, protecting against common DDoS attacks.'},
{id:'ccp36',exams:['ccp','saa'],domain:'Technology',text:'What is AWS Direct Connect?',options:['A VPN service','A dedicated private network connection from on-premises to AWS','A CDN service','A DNS routing policy'],correct:1,explanation:'AWS Direct Connect provides a dedicated private connection between your on-premises network and AWS, bypassing the public internet.'},
{id:'ccp37',exams:['ccp','saa'],domain:'Technology',text:'Which S3 storage class is designed for infrequently accessed data requiring rapid retrieval?',options:['S3 Standard','S3 Glacier','S3 Standard-IA','S3 One Zone-IA'],correct:2,explanation:'S3 Standard-IA is designed for data accessed less frequently but requiring rapid access. Lower storage cost but with a retrieval fee.'},
{id:'ccp38',exams:['ccp'],domain:'Billing & Pricing',text:'What does AWS Budgets allow you to do?',options:['Automatically reduce costs when overspending','Set custom cost and usage budgets and receive alerts when thresholds are exceeded','Pay your AWS bill automatically','Forecast future costs only'],correct:1,explanation:'AWS Budgets lets you set custom cost and usage budgets and receive alerts via email or SNS when thresholds are breached.'},
{id:'ccp39',exams:['ccp','saa'],domain:'Cloud Concepts',text:'What is an AWS Availability Zone?',options:['A geographic region where AWS operates','One or more discrete data centers with redundant power, networking, and connectivity','A content delivery point','A logical grouping of services'],correct:1,explanation:'An AZ consists of one or more discrete data centers with redundant power and networking, providing isolation from failures.'},
{id:'ccp40',exams:['ccp','dva'],domain:'Technology',text:'Which service combination enables serverless APIs?',options:['Amazon EC2','Amazon API Gateway + AWS Lambda','AWS Elastic Beanstalk','Amazon ECS'],correct:1,explanation:'API Gateway handles request routing and management while Lambda executes your code in response to HTTP requests, enabling serverless APIs.'},
{id:'ccp41',exams:['ccp'],domain:'Security & Compliance',text:'What is the purpose of AWS Trusted Advisor?',options:['Providing 24/7 human technical support','Offering real-time guidance following AWS best practices across cost, security, fault tolerance, performance, and service limits','Managing IAM users','Monitoring CloudTrail logs'],correct:1,explanation:'AWS Trusted Advisor provides recommendations across five categories: cost optimization, performance, security, fault tolerance, and service quotas.'},
{id:'ccp42',exams:['ccp','saa'],domain:'Technology',text:'What is Amazon Redshift?',options:['A messaging service','A fully managed data warehouse service','A NoSQL database','A caching solution'],correct:1,explanation:'Amazon Redshift is a fully managed, petabyte-scale data warehouse optimized for analytical (OLAP) workloads.'},
{id:'ccp43',exams:['ccp'],domain:'Cloud Concepts',text:'Which cloud deployment model keeps all infrastructure on-premises?',options:['Public cloud','Hybrid cloud','Private cloud','Community cloud'],correct:2,explanation:'A private cloud keeps all infrastructure on-premises, giving the organization full control without shared public infrastructure.'},
{id:'ccp44',exams:['ccp','saa','dva'],domain:'Technology',text:'What is Amazon ElastiCache used for?',options:['Storing large files','In-memory caching for low-latency data access','Running containerized workloads','Managing DNS records'],correct:1,explanation:'Amazon ElastiCache provides fully managed in-memory caching (Redis and Memcached) to improve application performance.'},
{id:'ccp45',exams:['ccp','saa','dva'],domain:'Security & Compliance',text:'What is AWS Config?',options:['A configuration file management service','Continuously monitors and records AWS resource configurations and evaluates compliance','A tool for setting up IAM policies','A cost anomaly detection service'],correct:1,explanation:'AWS Config continuously monitors and records AWS resource configurations, evaluating them against desired configurations for compliance.'},
{id:'ccp46',exams:['ccp','dva'],domain:'Technology',text:'What is Amazon SNS?',options:['A queue-based messaging service','A fully managed pub/sub messaging service for notifications and fan-out','A streaming data service','An email marketing platform'],correct:1,explanation:'Amazon SNS is a fully managed pub/sub messaging service that enables decoupling of microservices through topics and push notifications.'},
{id:'ccp47',exams:['ccp'],domain:'Billing & Pricing',text:'What is a Savings Plan in AWS?',options:['A retirement account offered by AWS','A flexible pricing model offering lower prices for a consistent usage commitment','A way to save your billing preferences','An automatic discount for enterprise customers'],correct:1,explanation:'AWS Savings Plans offer up to 72% savings on EC2, Lambda, and Fargate usage in exchange for a 1 or 3-year usage commitment.'},
{id:'ccp48',exams:['ccp'],domain:'Cloud Concepts',text:"What is the concept of 'fault tolerance'?",options:['The ability to process faults quickly','The ability of a system to continue operating even when components fail','The amount of time a system is expected to function','The geographic redundancy of cloud regions'],correct:1,explanation:'Fault tolerance is the ability of a system to remain operational when components fail, through redundancy and automatic failover.'},
{id:'ccp49',exams:['ccp','saa'],domain:'Technology',text:'Which AWS service provides global edge locations to reduce latency?',options:['AWS Direct Connect','Amazon CloudFront','Amazon Route 53','AWS Global Accelerator'],correct:3,explanation:'AWS Global Accelerator uses the AWS global network to route traffic to optimal endpoints, improving availability and performance.'},
{id:'ccp50',exams:['ccp'],domain:'Cloud Concepts',text:'What is a hybrid cloud deployment?',options:['Deploying all workloads to public cloud','Connecting on-premises infrastructure with cloud resources','Using multiple public cloud providers','A private data center with cloud-like management'],correct:1,explanation:'A hybrid cloud connects on-premises infrastructure with cloud resources, allowing workloads to run in the most appropriate environment.'},
{id:'ccp51',exams:['ccp'],domain:'Technology',text:'Which service provides a managed Apache Kafka offering on AWS?',options:['Amazon SQS','Amazon SNS','Amazon MSK','Amazon Kinesis'],correct:2,explanation:'Amazon MSK (Managed Streaming for Apache Kafka) is a fully managed service for Apache Kafka to process streaming data.'},
{id:'ccp52',exams:['ccp','saa'],domain:'Technology',text:'What is Amazon Aurora?',options:['A NoSQL database','A MySQL/PostgreSQL-compatible relational database with up to 5x performance','A data warehouse','An in-memory cache'],correct:1,explanation:'Amazon Aurora is a MySQL and PostgreSQL-compatible relational database that is up to 5x faster, with automated backups and multi-AZ replication.'},
{id:'ccp53',exams:['ccp'],domain:'Security & Compliance',text:'What is Amazon Macie?',options:['A DDoS protection service','A fully managed data security service using ML to discover and protect sensitive data in S3','An intrusion detection system','A key management service'],correct:1,explanation:'Amazon Macie uses machine learning to automatically discover, classify, and protect sensitive data stored in Amazon S3.'},
{id:'ccp54',exams:['ccp'],domain:'Cloud Concepts',text:'What does "pay-as-you-go" pricing mean in AWS?',options:['You pay upfront for a year of usage','You only pay for the resources you actually use, when you use them','You get a fixed monthly bill regardless of usage','You pay after a free 6-month trial'],correct:1,explanation:'Pay-as-you-go pricing means you pay only for the compute, storage, and other resources you actually use, with no long-term contracts.'},
{id:'ccp55',exams:['ccp'],domain:'Technology',text:'What is Amazon ECS?',options:['A managed Kubernetes service','A fully managed container orchestration service','A serverless function service','A CI/CD pipeline tool'],correct:1,explanation:'Amazon ECS (Elastic Container Service) is a fully managed container orchestration service for Docker containers.'},
{id:'ccp56',exams:['ccp'],domain:'Technology',text:'What is the purpose of an Internet Gateway in AWS?',options:['To connect VPCs to each other','To allow communication between a VPC and the internet','To route traffic between Availability Zones','To provide private connectivity to AWS services'],correct:1,explanation:'An Internet Gateway enables communication between instances in your VPC and the internet.'},
{id:'ccp57',exams:['ccp'],domain:'Security & Compliance',text:'What is AWS Security Hub?',options:['A physical security operations center','A service that provides a comprehensive view of security alerts and compliance status across accounts','A VPN management tool','A firewall configuration service'],correct:1,explanation:'AWS Security Hub gives a centralized view of security alerts and compliance status across your AWS accounts and services.'},
{id:'ccp58',exams:['ccp'],domain:'Billing & Pricing',text:'What is a Reserved Instance?',options:['An instance that is always running and cannot be stopped','A pricing model offering discounts in exchange for commitment to a specific instance type over 1 or 3 years','An instance reserved for AWS internal use','A dedicated physical server'],correct:1,explanation:'Reserved Instances offer significant discounts (up to 72%) compared to On-Demand in exchange for committing to a specific instance configuration.'},
{id:'ccp59',exams:['ccp'],domain:'Cloud Concepts',text:'What is AWS CloudFormation?',options:['A weather monitoring service','An infrastructure as code service for provisioning AWS resources','A code repository service','A monitoring service'],correct:1,explanation:'AWS CloudFormation is an IaC (Infrastructure as Code) service that uses templates to provision and manage AWS resources.'},
{id:'ccp60',exams:['ccp'],domain:'Technology',text:'What does Auto Scaling do?',options:['Manually increases server size','Automatically adjusts the number of EC2 instances based on demand','Migrates databases automatically','Manages DNS routing'],correct:1,explanation:'Auto Scaling automatically adjusts the number of EC2 instances in response to demand, ensuring availability and reducing costs.'},
{id:'ccp61',exams:['ccp'],domain:'Security & Compliance',text:'What is a Security Group in AWS?',options:['A team of AWS security specialists','A virtual firewall that controls inbound and outbound traffic for EC2 instances','A group of IAM users with shared permissions','An encryption key group'],correct:1,explanation:'A Security Group acts as a virtual firewall at the instance level, controlling inbound and outbound traffic for EC2 instances.'},
{id:'ccp62',exams:['ccp'],domain:'Technology',text:'What is Amazon EBS?',options:['An email service','Block storage volumes for use with EC2 instances','An elastic load balancer','An object storage service'],correct:1,explanation:'Amazon EBS (Elastic Block Store) provides persistent block storage volumes that attach to EC2 instances, similar to a hard drive.'},
{id:'ccp63',exams:['ccp'],domain:'Technology',text:'What is the purpose of AWS CloudWatch?',options:['Storing code repositories','Monitoring resources and applications, collecting metrics and logs','Automating software deployments','Managing user identities'],correct:1,explanation:'Amazon CloudWatch monitors AWS resources and applications, collecting metrics, logs, and events to provide operational visibility.'},
{id:'ccp64',exams:['ccp'],domain:'Cloud Concepts',text:'What does "agility" mean in the context of cloud computing?',options:['The speed of physical server delivery','The ability to quickly provision and deprovision resources, reducing time to experiment and deploy','The geographic speed of data transfer','The flexibility to change cloud providers'],correct:1,explanation:'Cloud agility means being able to quickly spin up resources needed for experiments and deploying new applications in minutes.'},
{id:'ccp65',exams:['ccp'],domain:'Security & Compliance',text:'What is Multi-Factor Authentication (MFA) in AWS?',options:['Using multiple AWS accounts','Requiring two or more verification factors to gain access','Having multiple passwords','Using multiple IAM roles simultaneously'],correct:1,explanation:'MFA adds an extra layer of security by requiring users to provide two or more verification factors in addition to their password.'},
{id:'ccp66',exams:['ccp'],domain:'Technology',text:'What is Amazon Lightsail?',options:['A lightweight version of EC2','An easy-to-use cloud platform for simple web apps, websites, and small databases with predictable pricing','A low-power IoT device service','A simplified S3 storage tier'],correct:1,explanation:'Amazon Lightsail is designed for simpler use cases like websites and small apps, offering preconfigured VPS with predictable monthly pricing.'},
{id:'ccp67',exams:['ccp'],domain:'Billing & Pricing',text:'What is the AWS Cost and Usage Report (CUR)?',options:['A daily email with cost summaries','The most comprehensive set of AWS cost and usage data, including metadata about services and pricing','A simplified one-page bill','An automated cost reduction tool'],correct:1,explanation:'The CUR provides the most detailed data about your AWS costs and usage, including hourly/daily breakdowns with resource-level granularity.'},
{id:'ccp68',exams:['ccp'],domain:'Technology',text:'What is AWS Step Functions?',options:['A manual process documentation tool','A serverless orchestration service for coordinating components of distributed applications','A testing framework for Lambda functions','A CI/CD service'],correct:1,explanation:'AWS Step Functions orchestrates serverless workflows, letting you coordinate Lambda functions and other services into resilient business processes.'},
{id:'ccp69',exams:['ccp'],domain:'Cloud Concepts',text:'What is the benefit of using multiple Availability Zones?',options:['Lower network latency between servers','Increased fault tolerance and high availability by isolating failures to a single AZ','Reduced AWS pricing','Simplified IAM management'],correct:1,explanation:'Using multiple AZs means a failure in one AZ does not affect your application in other AZs, providing high availability and fault tolerance.'},
{id:'ccp70',exams:['ccp'],domain:'Technology',text:'What is Amazon Kinesis Data Streams used for?',options:['Storing video files','Collecting and processing large streams of data records in real time','Queuing messages for async processing','Storing structured relational data'],correct:1,explanation:'Amazon Kinesis Data Streams captures, processes, and stores data streams in real time, enabling real-time analytics and processing.'},
{id:'ccp71',exams:['ccp'],domain:'Security & Compliance',text:'What is the purpose of AWS KMS?',options:['Kubernetes management service','Create and manage cryptographic keys and control their use across AWS services and applications','Key performance monitoring service','A VPN key exchange service'],correct:1,explanation:'AWS KMS (Key Management Service) lets you create and control cryptographic keys used to encrypt your data across AWS services.'},
{id:'ccp72',exams:['ccp'],domain:'Technology',text:'What is Amazon EFS?',options:['A block storage service','An elastic file system that provides scalable shared file storage for EC2 instances','An email filtering service','An edge caching service'],correct:1,explanation:'Amazon EFS (Elastic File System) provides scalable, shared NFS file storage that can be mounted by multiple EC2 instances simultaneously.'},
{id:'ccp73',exams:['ccp'],domain:'Billing & Pricing',text:'What is AWS Organizations used for?',options:['Managing employee org charts','Centrally managing multiple AWS accounts, applying policies, and consolidating billing','Organizing S3 buckets into folders','Grouping EC2 instances by team'],correct:1,explanation:'AWS Organizations lets you centrally manage multiple accounts, apply Service Control Policies (SCPs), and consolidate billing across accounts.'},
{id:'ccp74',exams:['ccp'],domain:'Technology',text:'What is the purpose of an Elastic Load Balancer (ELB)?',options:['Increasing the memory of EC2 instances','Distributing incoming application traffic across multiple targets to increase availability','Elastically sizing storage volumes','Reducing the cost of data transfer'],correct:1,explanation:'ELB automatically distributes incoming traffic across multiple targets (EC2, containers, IPs) improving availability and fault tolerance.'},
{id:'ccp75',exams:['ccp'],domain:'Cloud Concepts',text:'What does "global infrastructure" mean in AWS?',options:['AWS has offices in every country','AWS operates Regions and Availability Zones worldwide to serve customers globally with low latency','AWS provides translation services globally','AWS data is shared across all countries'],correct:1,explanation:"AWS's global infrastructure spans Regions and AZs worldwide, allowing customers to serve end users with low latency wherever they are."},
{id:'ccp76',exams:['ccp'],domain:'Security & Compliance',text:'What is a Network Access Control List (NACL)?',options:['A list of approved IP addresses for SSH access','An optional layer of security acting as a firewall for controlling traffic in and out of subnets','A list of network administrators','An approved list of AWS services you can use'],correct:1,explanation:'NACLs act as a stateless firewall at the subnet level, controlling inbound and outbound traffic with numbered rules.'},
{id:'ccp77',exams:['ccp'],domain:'Technology',text:'What is AWS Glue?',options:['A tool to attach EBS volumes to EC2','A fully managed ETL (extract, transform, load) service for data integration','A service for merging multiple AWS accounts','A code compilation service'],correct:1,explanation:'AWS Glue is a serverless data integration service that makes it easier to discover, prepare, move, and integrate data for analytics.'},
{id:'ccp78',exams:['ccp'],domain:'Technology',text:'What is Amazon Athena?',options:['A monitoring dashboard service','An interactive query service to analyze data directly in S3 using SQL','A real-time streaming service','A machine learning training service'],correct:1,explanation:'Amazon Athena lets you run SQL queries directly against data stored in Amazon S3 with no infrastructure to manage, paying per query.'},
{id:'ccp79',exams:['ccp'],domain:'Cloud Concepts',text:'Which AWS service provides recommendations to reduce costs based on actual usage?',options:['AWS Pricing Calculator','AWS Trusted Advisor','AWS Budgets','AWS Cost Explorer'],correct:1,explanation:'AWS Trusted Advisor analyzes your usage and provides recommendations for cost savings, including identifying idle or underutilized resources.'},
{id:'ccp80',exams:['ccp'],domain:'Technology',text:'What is Amazon Comprehend?',options:['A training platform for developers','A natural language processing (NLP) service that finds insights in text','A document storage service','A code comprehension tool'],correct:1,explanation:'Amazon Comprehend uses machine learning to find insights and relationships in unstructured text without requiring ML expertise.'},
{id:'ccp81',exams:['ccp'],domain:'Security & Compliance',text:'What is AWS Secrets Manager?',options:['A service for managing classified government information','Stores, rotates, and retrieves database credentials, API keys, and other secrets','A physical key storage device','An IAM password management tool'],correct:1,explanation:'AWS Secrets Manager helps protect access to applications by securely storing, managing, and rotating secrets like database credentials and API keys.'},
{id:'ccp82',exams:['ccp'],domain:'Technology',text:'What is Amazon SageMaker?',options:['A project management tool','A fully managed service to build, train, and deploy machine learning models at scale','A Kubernetes management service','A streaming media service'],correct:1,explanation:'Amazon SageMaker provides every developer and data scientist with the ability to build, train, and deploy ML models quickly.'},
{id:'ccp83',exams:['ccp'],domain:'Cloud Concepts',text:'What is cloud bursting?',options:['When a cloud server crashes under heavy load','A deployment strategy where an application runs in a private cloud but bursts into a public cloud when demand spikes','Exceeding your AWS account limits','A form of data breach'],correct:1,explanation:'Cloud bursting lets applications run in a private cloud but automatically expand into public cloud resources when demand exceeds private capacity.'},
{id:'ccp84',exams:['ccp'],domain:'Technology',text:'What does Amazon Rekognition do?',options:['Manages code repositories','Provides image and video analysis using machine learning','Monitors application performance','Recognizes and routes DNS requests'],correct:1,explanation:'Amazon Rekognition is a computer vision service that adds image and video analysis to your applications using deep learning.'},
{id:'ccp85',exams:['ccp'],domain:'Billing & Pricing',text:'What is an AWS account root user?',options:['The first IAM user created','The identity created when you first create an AWS account with full access to all services and resources','A special administrator role','An account used for billing only'],correct:1,explanation:'The root user is created when you first set up an AWS account and has unrestricted access. Best practice is to use IAM users for daily tasks.'},
{id:'ccp86',exams:['ccp'],domain:'Technology',text:'What is Amazon Polly?',options:['A polling service for surveys','A service that turns text into lifelike speech','A real-time data polling service','A network monitoring tool'],correct:1,explanation:'Amazon Polly uses advanced deep learning to synthesize natural-sounding human speech from text.'},
{id:'ccp87',exams:['ccp'],domain:'Technology',text:'What is AWS DataSync?',options:['A database synchronization tool','A service that automates and accelerates moving data between on-premises storage and AWS','A real-time data streaming service','A database migration tool'],correct:1,explanation:'AWS DataSync simplifies, automates, and accelerates the transfer of data between on-premises storage systems and AWS storage services.'},
{id:'ccp88',exams:['ccp'],domain:'Security & Compliance',text:'What is Amazon Cognito?',options:['A cognitive computing platform','A service for adding user sign-up, sign-in, and access control to web and mobile apps','A database with cognitive features','An AI-powered security service'],correct:1,explanation:'Amazon Cognito lets you add user authentication and authorization to your web and mobile apps quickly and easily.'},
{id:'ccp89',exams:['ccp'],domain:'Technology',text:'What is AWS IoT Core?',options:['A service for managing on-premises servers','A managed cloud service for connecting IoT devices securely to the cloud','An internet speed testing service','A core networking component for VPCs'],correct:1,explanation:'AWS IoT Core is a managed service that lets connected devices interact securely with cloud applications and other devices.'},
{id:'ccp90',exams:['ccp'],domain:'Cloud Concepts',text:'What is the AWS Marketplace?',options:['A physical store for AWS hardware','An online catalog of thousands of software listings from independent software vendors to run on AWS','A job board for AWS professionals','A marketplace for selling unused Reserved Instances'],correct:1,explanation:'AWS Marketplace is a digital catalog of third-party software, data, and services that run on AWS, simplifying procurement and deployment.'},
{id:'ccp91',exams:['ccp'],domain:'Technology',text:'What is Amazon Translate?',options:['A document conversion service','A neural machine translation service for fast, high-quality language translation','A DNS translation service','A code language translator'],correct:1,explanation:'Amazon Translate is a neural machine translation service that delivers fast, high-quality, and affordable language translation.'},
{id:'ccp92',exams:['ccp'],domain:'Security & Compliance',text:'What is AWS Control Tower?',options:['A physical control room for AWS operations','A service to set up and govern a secure, multi-account AWS environment following best practices','A network traffic control service','A monitoring dashboard'],correct:1,explanation:'AWS Control Tower automates the set up of a baseline environment (landing zone) for multi-account governance following AWS best practices.'},
{id:'ccp93',exams:['ccp'],domain:'Technology',text:'What is Amazon Forecast?',options:['A weather prediction service','A fully managed service using ML to deliver highly accurate time-series forecasts','A financial planning tool','A capacity planning dashboard'],correct:1,explanation:'Amazon Forecast uses machine learning to generate accurate forecasts from time-series data without requiring ML expertise.'},
{id:'ccp94',exams:['ccp'],domain:'Billing & Pricing',text:'What is the difference between CapEx and OpEx in cloud computing?',options:['CapEx is cloud costs, OpEx is on-premises costs','CapEx is upfront capital investment (on-premises); OpEx is ongoing operational spend (cloud pay-as-you-go)','There is no difference','CapEx is cheaper than OpEx always'],correct:1,explanation:'Traditional IT uses CapEx (large upfront investment in hardware). Cloud shifts this to OpEx (ongoing operational expenses), improving cash flow.'},
{id:'ccp95',exams:['ccp'],domain:'Technology',text:'What is AWS CodePipeline?',options:['A visual code editor','A fully managed continuous delivery service for automating release pipelines','A code review tool','A performance testing service'],correct:1,explanation:'AWS CodePipeline is a fully managed CD service that automates your build, test, and deploy phases each time there is a code change.'},
{id:'ccp96',exams:['ccp'],domain:'Security & Compliance',text:'What is a VPN in AWS context?',options:['Virtual Private Network providing encrypted tunnel between on-premises and VPC over the internet','A type of EC2 instance','A Virtual Private Node in a cluster','A billing category'],correct:0,explanation:'An AWS VPN creates an encrypted tunnel between your on-premises network (or client) and your Amazon VPC over the public internet.'},
{id:'ccp97',exams:['ccp'],domain:'Technology',text:'What is Amazon Lex?',options:['A legal document service','A service for building conversational interfaces using voice and text (chatbots)','A lexical analysis tool for code','A networking service'],correct:1,explanation:'Amazon Lex is a service for building conversational interfaces using automatic speech recognition and natural language understanding.'},
{id:'ccp98',exams:['ccp'],domain:'Cloud Concepts',text:'What is the purpose of AWS Personal Health Dashboard?',options:['Monitoring your physical health data','Providing personalized alerts about AWS service events that may affect your resources','Showing the health of your EC2 instances','Displaying your billing health'],correct:1,explanation:'AWS Health Dashboard provides personalized alerts and remediation guidance when AWS is experiencing events that may affect your resources.'},
{id:'ccp99',exams:['ccp'],domain:'Technology',text:'What is Amazon Textract?',options:['A text editing service','A service that automatically extracts text, forms, and tables from scanned documents','A text translation service','A content moderation service'],correct:1,explanation:'Amazon Textract uses ML to automatically extract text and data from scanned documents, going beyond simple OCR to identify structure.'},
{id:'ccp100',exams:['ccp'],domain:'Technology',text:'What is the AWS Snow Family?',options:['A series of winter-themed promotional events','Physical devices for migrating large amounts of data into and out of AWS when internet transfer is impractical','A family of lightweight EC2 instances for cold storage','AWS services for Scandinavian customers'],correct:1,explanation:'The AWS Snow Family (Snowcone, Snowball, Snowmobile) are physical devices used to transfer large amounts of data to AWS when network transfer is too slow or impractical.'},
{id:'ccp101',exams:['ccp'],domain:'Security & Compliance',text:'What is AWS WAF used to protect against?',options:['Physical theft of AWS servers','Common web attacks like SQL injection, cross-site scripting (XSS), and DDoS','Unauthorized AWS account access','Data corruption in S3'],correct:1,explanation:'AWS WAF protects web applications by filtering malicious web traffic, blocking common attack patterns like SQL injection and XSS.'},
{id:'ccp102',exams:['ccp'],domain:'Technology',text:'What is Amazon Connect?',options:['A physical networking service','An omnichannel cloud contact center service','A service for connecting VPCs','A partner integration portal'],correct:1,explanation:'Amazon Connect is an easy-to-use omnichannel cloud contact center helping companies provide superior customer service at lower cost.'},
{id:'ccp103',exams:['ccp'],domain:'Billing & Pricing',text:'What does "right-sizing" mean in AWS?',options:['Physically sizing servers correctly','Matching instance types and sizes to actual workload requirements to reduce costs','Sizing your S3 buckets','Standardizing on one instance family'],correct:1,explanation:'Right-sizing means analyzing and selecting the most cost-effective EC2 instance types/sizes that still meet your performance requirements.'},
{id:'ccp104',exams:['ccp'],domain:'Cloud Concepts',text:'What is the AWS Well-Architected Tool?',options:['A physical measurement tool for data centers','A service that helps review the state of your workloads against AWS best practices','A code quality measurement tool','A project management tool'],correct:1,explanation:'The AWS Well-Architected Tool helps you review your architecture against best practices across the six pillars and provides guidance for improvements.'},
{id:'ccp105',exams:['ccp'],domain:'Technology',text:'What is AWS Batch?',options:['A batch cooking delivery service','A fully managed service for running hundreds of thousands of batch computing jobs on AWS','A bulk S3 file upload tool','A group messaging service'],correct:1,explanation:'AWS Batch dynamically provisions compute resources and schedules batch computing jobs based on volume and resource requirements.'},
{id:'ccp106',exams:['ccp'],domain:'Security & Compliance',text:'What is the AWS Acceptable Use Policy?',options:['A document describing acceptable server room temperatures','A policy describing prohibited uses of AWS services','A guide to acceptable IAM policy syntax','A billing usage agreement'],correct:1,explanation:'The AWS Acceptable Use Policy (AUP) describes prohibited uses of AWS services, including illegal activity, harmful content, and security violations.'},
{id:'ccp107',exams:['ccp'],domain:'Technology',text:'What is Amazon Transcribe?',options:['A document scanning service','An automatic speech recognition service that converts audio to text','A text copy service','A language learning platform'],correct:1,explanation:'Amazon Transcribe uses automatic speech recognition (ASR) to convert speech to text, useful for transcribing customer calls and media content.'},
{id:'ccp108',exams:['ccp'],domain:'Cloud Concepts',text:'What is an IAM policy?',options:['A physical security policy for data centers','A document that defines permissions and access controls for AWS resources','A billing policy for reserved instances','A network routing policy'],correct:1,explanation:'An IAM policy is a JSON document that defines permissions, specifying which actions are allowed or denied on which AWS resources.'},
{id:'ccp109',exams:['ccp'],domain:'Technology',text:'What does AWS X-Ray do?',options:['X-ray scanning of server hardware','Analyzes and debugs distributed applications, providing end-to-end tracing','A penetration testing service','A data visualization tool'],correct:1,explanation:'AWS X-Ray helps developers analyze and debug distributed applications by providing end-to-end view of requests and identifying performance bottlenecks.'},
{id:'ccp110',exams:['ccp'],domain:'Billing & Pricing',text:'What is a Dedicated Host?',options:['A hosting plan for dedicated websites','A physical EC2 server fully dedicated to your use, allowing you to bring existing server-bound software licenses','A private S3 bucket','A reserved support engineer'],correct:1,explanation:'A Dedicated Host is a physical server with EC2 instance capacity fully dedicated to your use, useful for regulatory requirements and BYOL licensing.'},
{id:'ccp111',exams:['ccp'],domain:'Technology',text:'What is Amazon Timestream?',options:['A video timestamp service','A fast, scalable, fully managed time series database for IoT and operational applications','A calendar service','A scheduling service'],correct:1,explanation:'Amazon Timestream is a purpose-built time series database that makes it easy and cost-effective to store and analyze trillions of time series data points.'},
{id:'ccp112',exams:['ccp'],domain:'Security & Compliance',text:'What is Amazon Detective?',options:['A mystery puzzle game service','A service that analyzes and visualizes security data to help investigate potential security issues','A fraud detection service for e-commerce','A code vulnerability scanner'],correct:1,explanation:'Amazon Detective makes it easy to analyze, investigate, and quickly identify the root cause of potential security issues or suspicious activities.'},
{id:'ccp113',exams:['ccp'],domain:'Cloud Concepts',text:'What is a Service Level Agreement (SLA) in AWS?',options:['A signed agreement with your AWS account manager','A commitment by AWS to a specific level of service uptime/performance, with credits if not met','A list of all AWS service features','A support contract'],correct:1,explanation:'An SLA is a formal commitment by AWS about service availability. If the SLA is not met, customers may receive service credits.'},
{id:'ccp114',exams:['ccp'],domain:'Technology',text:'What is AWS AppSync?',options:['A mobile app synchronization backup service','A managed GraphQL service for building scalable APIs that connect apps to data and services','An app deployment synchronization tool','A calendar sync service'],correct:1,explanation:'AWS AppSync is a managed GraphQL service that simplifies app development by creating a flexible API to securely access, manipulate, and combine data from multiple sources.'},
{id:'ccp115',exams:['ccp'],domain:'Technology',text:'What is Amazon Kendra?',options:['A Kenyan customer service portal','An intelligent enterprise search service powered by ML','A key-value database','A container registry'],correct:1,explanation:'Amazon Kendra is an intelligent enterprise search service that uses natural language processing and ML to return accurate search results from your content repositories.'},
{id:'ccp116',exams:['ccp'],domain:'Security & Compliance',text:'What does AWS Shield Advanced provide beyond Shield Standard?',options:['Nothing - they are identical','24/7 access to the AWS DDoS Response Team, detailed attack diagnostics, and financial protection against scaling charges','Only email alerts for attacks','Protection for on-premises infrastructure only'],correct:1,explanation:'AWS Shield Advanced adds DDoS Response Team support, detailed metrics, attack notifications, and cost protection for scaling charges caused by DDoS attacks.'},
{id:'ccp117',exams:['ccp'],domain:'Technology',text:'What is Amazon DocumentDB?',options:['A physical document archive service','A managed document database service compatible with MongoDB','A service for storing PDF files','A document collaboration tool'],correct:1,explanation:'Amazon DocumentDB is a fully managed MongoDB-compatible document database service, designed for JSON workloads at scale.'},
{id:'ccp118',exams:['ccp'],domain:'Cloud Concepts',text:'What is the AWS Partner Network (APN)?',options:['A personal networking group for AWS employees','A global community of consulting and technology partners who help customers build on AWS','A peer-to-peer networking protocol for EC2','A referral program for individual users'],correct:1,explanation:'The APN is a global ecosystem of partners—consultants, ISVs, and technology providers—that help customers design, architect, and build on AWS.'},
{id:'ccp119',exams:['ccp'],domain:'Technology',text:'What is Amazon Neptune?',options:['A space exploration data service','A fully managed graph database service for building applications with connected data','A deep ocean data analytics service','A high-performance computing cluster'],correct:1,explanation:'Amazon Neptune is a fully managed graph database that supports the Property Graph and RDF models, ideal for social networks, knowledge graphs, and fraud detection.'},
{id:'ccp120',exams:['ccp'],domain:'Billing & Pricing',text:'What is the purpose of AWS Cost Anomaly Detection?',options:['Detecting fraudulent AWS accounts','Using ML to continuously monitor costs and alert you to unusual spend patterns','Identifying security anomalies','Detecting performance anomalies'],correct:1,explanation:'AWS Cost Anomaly Detection uses ML to identify unusual spending patterns, sending alerts when costs behave differently from expected norms.'},
{id:'ccp121',exams:['ccp'],domain:'Technology',text:'What is Amazon WorkSpaces?',options:['A coworking space booking service','A managed, persistent cloud desktop (DaaS) solution','A project management tool','A code collaboration environment'],correct:1,explanation:'Amazon WorkSpaces is a fully managed Desktop as a Service (DaaS) solution that gives users access to a cloud desktop from any device.'},
{id:'ccp122',exams:['ccp'],domain:'Security & Compliance',text:'What is the difference between authentication and authorization in IAM?',options:['They are the same thing','Authentication verifies who you are; authorization determines what you are allowed to do','Authentication manages billing; authorization manages networking','Authentication is for humans; authorization is for services'],correct:1,explanation:'Authentication (who are you?) uses credentials to verify identity. Authorization (what can you do?) uses policies to determine allowed actions.'},
{id:'ccp123',exams:['ccp'],domain:'Technology',text:'What is AWS Transit Gateway?',options:['A toll payment gateway for internet traffic','A service that connects VPCs and on-premises networks through a central hub','An internet gateway for large enterprises','A payment gateway for AWS Marketplace'],correct:1,explanation:'AWS Transit Gateway acts as a cloud router, connecting VPCs and on-premises networks through a central hub, simplifying network topology.'},
{id:'ccp124',exams:['ccp'],domain:'Technology',text:'What is Amazon Quantum Ledger Database (QLDB)?',options:['A quantum computing database','A fully managed ledger database providing a cryptographically verifiable transaction log','A database for financial quantum models','A ledger for tracking AWS service usage'],correct:1,explanation:'Amazon QLDB is a fully managed ledger database with a transparent, immutable, and cryptographically verifiable transaction log.'},
{id:'ccp125',exams:['ccp'],domain:'Cloud Concepts',text:'What is the purpose of AWS service quotas (formerly limits)?',options:['To prevent customers from using too many services','Maximum values for resources and API requests to protect the AWS infrastructure and the customer account','Price limits on AWS services','The number of support cases you can open'],correct:1,explanation:'Service quotas are limits on the maximum number of resources you can create and the rate of API calls, protecting both AWS infrastructure and your account.'},
{id:'ccp126',exams:['ccp'],domain:'Technology',text:'What is Amazon EventBridge?',options:['An event venue booking service','A serverless event bus that connects applications using real-time data from your own apps, SaaS, and AWS services','A physical event monitoring dashboard','A bridge between two VPCs'],correct:1,explanation:'Amazon EventBridge is a serverless event bus that makes it easier to build event-driven applications using events from AWS services, your apps, and SaaS.'},
{id:'ccp127',exams:['ccp'],domain:'Security & Compliance',text:'What is IAM Identity Center (formerly SSO)?',options:['A single sign-on service for websites','A service for centrally managing SSO access to multiple AWS accounts and business applications','A two-factor authentication service','An identity theft protection service'],correct:1,explanation:'AWS IAM Identity Center provides centralized SSO access to all your AWS accounts and business applications from one place.'},
{id:'ccp128',exams:['ccp'],domain:'Technology',text:'What is Amazon MemoryDB for Redis?',options:['A physical memory management tool','A Redis-compatible, durable, in-memory database service for ultra-fast performance','A memory profiling service','A Redis documentation service'],correct:1,explanation:'Amazon MemoryDB for Redis is a Redis-compatible, fully managed in-memory database that provides fast performance with Multi-AZ durability.'},
{id:'ccp129',exams:['ccp'],domain:'Cloud Concepts',text:'What is "infrastructure as code" (IaC)?',options:['Writing code that runs on physical infrastructure only','Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes','A programming language for hardware','Infrastructure monitoring using code metrics'],correct:1,explanation:'IaC manages infrastructure through code (like CloudFormation or Terraform), enabling version control, automation, and repeatable deployments.'},
{id:'ccp130',exams:['ccp'],domain:'Technology',text:'What is AWS CodeBuild?',options:['A visual website builder','A fully managed build service that compiles source code, runs tests, and produces deployment artifacts','A CI/CD pipeline service','A code review tool'],correct:1,explanation:'AWS CodeBuild is a fully managed continuous integration service that compiles source code, runs unit tests, and produces ready-to-deploy software packages.'},
{id:'ccp131',exams:['ccp'],domain:'Security & Compliance',text:'What is VPC Flow Logs?',options:['A log of all network requests to websites','Captures information about IP traffic going to and from network interfaces in your VPC','A log of all API calls','A physical network cable log'],correct:1,explanation:'VPC Flow Logs capture information about the IP traffic going to and from network interfaces in your VPC for security and troubleshooting.'},
{id:'ccp132',exams:['ccp'],domain:'Technology',text:'What is AWS Outposts?',options:['Remote AWS offices','Fully managed infrastructure that extends AWS services and APIs to virtually any on-premises or edge location','Outdoor surveillance services','External partner network nodes'],correct:1,explanation:'AWS Outposts brings native AWS services, infrastructure, and operating models to on-premises and edge locations for hybrid cloud deployments.'},
{id:'ccp133',exams:['ccp'],domain:'Billing & Pricing',text:'What is AWS Compute Optimizer?',options:['A tool to physically optimize server hardware','Recommends optimal AWS compute resources (EC2, Lambda, EBS) based on actual usage data to reduce costs','A cost comparison service for different cloud providers','A calculator for compute pricing'],correct:1,explanation:'AWS Compute Optimizer uses ML to analyze usage metrics and recommend optimal compute resources to reduce costs and improve performance.'},
{id:'ccp134',exams:['ccp'],domain:'Technology',text:'What is AWS Wavelength?',options:['A radio frequency management service','Infrastructure deployments within telecom providers to deliver ultra-low latency apps for 5G mobile devices','A light-based networking standard','A low-power IoT wireless protocol'],correct:1,explanation:'AWS Wavelength embeds compute and storage within 5G networks, enabling developers to build ultra-low-latency applications for mobile edge computing.'},
{id:'ccp135',exams:['ccp'],domain:'Cloud Concepts',text:'What does TCO (Total Cost of Ownership) mean in cloud context?',options:['The total cost of your monthly AWS bill only','The full cost comparison including hardware, software, staff, facilities, and operational costs of on-premises vs cloud','The cost of transferring data out of AWS','The total number of services you use'],correct:1,explanation:'TCO analysis compares the total costs of running on-premises (hardware, facilities, staff, software) vs cloud, often showing cloud has lower TCO.'},
{id:'ccp136',exams:['ccp'],domain:'Technology',text:'What is Amazon Keyspaces?',options:['A key management service','A scalable, serverless, and highly available Apache Cassandra-compatible database service','A keyboard shortcut service','A key-value store optimized for gaming'],correct:1,explanation:'Amazon Keyspaces is a serverless, Apache Cassandra-compatible database service that is scalable, available, and fully managed.'},
{id:'ccp137',exams:['ccp'],domain:'Technology',text:'What is AWS Lake Formation?',options:['A water management service','A service that makes it easy to set up a secure data lake in days','A cloud storage tier for archives','A formation training service'],correct:1,explanation:'AWS Lake Formation simplifies the creation of secure data lakes, handling the complex tasks of data ingestion, cataloging, security, and governance.'},
{id:'ccp138',exams:['ccp'],domain:'Security & Compliance',text:'What is an IAM Role?',options:['A job title for AWS employees','An IAM identity that can be assumed by services, applications, or users that need temporary access to AWS resources','A permanent set of permissions for a user','An EC2 instance type designation'],correct:1,explanation:'IAM Roles provide temporary credentials and are assumed by EC2 instances, Lambda functions, or users to access AWS resources without embedding credentials.'},
{id:'ccp139',exams:['ccp'],domain:'Technology',text:'What is Amazon Lookout for Metrics?',options:['A telescope rental service','A service that uses ML to automatically detect anomalies in business metrics and identify their root causes','A performance monitoring dashboard','A KPI tracking spreadsheet'],correct:1,explanation:'Amazon Lookout for Metrics automatically detects and diagnoses anomalies in business and operational metrics using ML, without requiring ML expertise.'},
{id:'ccp140',exams:['ccp'],domain:'Cloud Concepts',text:'What is an S3 bucket policy?',options:['A lifecycle policy for objects','A resource-based policy attached to an S3 bucket that grants access permissions to the bucket and the objects in it','A CORS policy for S3','A replication policy'],correct:1,explanation:'An S3 bucket policy is a JSON-based resource policy that controls access to an S3 bucket and its objects, allowing or denying specific actions.'},
{id:'ccp141',exams:['ccp'],domain:'Technology',text:'What is Amazon CloudSearch?',options:['A legal discovery tool','A fully managed search service that makes it easy to set up, manage, and scale a search solution for your website or application','A cloud provider comparison site','A DNS search service'],correct:1,explanation:'Amazon CloudSearch is a fully managed service that makes it easy to set up, manage, and scale a custom search solution.'},
{id:'ccp142',exams:['ccp'],domain:'Technology',text:'What is Amazon Pinpoint?',options:['A GPS location service','A flexible marketing communications service for sending targeted messages via email, SMS, push, and voice','A map annotation tool','A precision time synchronization service'],correct:1,explanation:'Amazon Pinpoint is a flexible communications service for marketing, transactional, and bulk messaging campaigns via email, SMS, push, and voice channels.'},
{id:'ccp143',exams:['ccp'],domain:'Security & Compliance',text:'What is AWS Certificate Manager (ACM)?',options:['A diploma verification service','Provisions, manages, and deploys SSL/TLS certificates for use with AWS services','A compliance certification tracker','A management certification training service'],correct:1,explanation:'AWS ACM handles the complexity of creating, storing, and renewing SSL/TLS certificates for use with AWS services at no cost.'},
{id:'ccp144',exams:['ccp'],domain:'Technology',text:'What is AWS CodeDeploy?',options:['A cloud storage deployment','A fully managed deployment service that automates software deployments to EC2, Lambda, and on-premises servers','A code distribution CDN','A developer marketplace'],correct:1,explanation:'AWS CodeDeploy automates code deployments to any instance—including EC2, Lambda, and on-premises—minimizing downtime during application updates.'},
{id:'ccp145',exams:['ccp'],domain:'Cloud Concepts',text:'What is the difference between public and private subnets in a VPC?',options:['Public subnets cost more','Public subnets have a route to an internet gateway; private subnets do not, making resources inaccessible from the internet','Public subnets are for databases; private subnets are for web servers','There is no difference'],correct:1,explanation:'Public subnets route traffic to an internet gateway, enabling direct internet access. Private subnets have no internet gateway route, keeping resources isolated.'},
{id:'ccp146',exams:['ccp'],domain:'Technology',text:'What is Amazon Fraud Detector?',options:['A physical fraud investigation service','A fully managed service using ML to identify potentially fraudulent online activities','A financial audit tool','A customer identity verification service'],correct:1,explanation:'Amazon Fraud Detector uses ML to detect potentially fraudulent activities online, such as fake accounts and payment fraud, in real time.'},
{id:'ccp147',exams:['ccp'],domain:'Technology',text:'What is AWS Ground Station?',options:['A weather station monitoring service','A fully managed service to control satellite communications, process data, and scale operations','A ground transportation logistics tool','An underground data center tier'],correct:1,explanation:'AWS Ground Station is a fully managed service for controlling satellite communications and processing satellite data using AWS global infrastructure.'},
{id:'ccp148',exams:['ccp'],domain:'Billing & Pricing',text:'What is the purpose of Resource Tags in AWS billing?',options:['To label physical servers','To categorize AWS resources for cost allocation, allowing you to track spending by project, team, or environment','To tag security vulnerabilities','To label public IP addresses'],correct:1,explanation:'Resource tags are key-value pairs applied to AWS resources. Cost allocation tags help you track and allocate costs to specific projects or teams.'},
{id:'ccp149',exams:['ccp'],domain:'Technology',text:'What is Amazon AppStream 2.0?',options:['A music streaming service','A fully managed application streaming service that delivers desktop applications to any device through a browser','A video live-streaming platform','An app update distribution service'],correct:1,explanation:'Amazon AppStream 2.0 streams desktop applications from AWS to any device with a web browser, without needing to install applications locally.'},
{id:'ccp150',exams:['ccp'],domain:'Cloud Concepts',text:'What is the AWS Command Line Interface (CLI)?',options:['A physical hardware control panel','A unified tool to manage AWS services from the command line, enabling scripting and automation','A web-based management console','A chat-based support tool'],correct:1,explanation:'The AWS CLI allows you to interact with AWS services using commands in your terminal, enabling automation and scripting of AWS operations.'},
];
